    const result = await renderViewerHtml(mockHtml, rewrittenCss, TEST_CDN_BASE, TEST_VIEWER_URLS)
    expect(result).toContain('<style>')
    expect(result).toContain(`url(${TEST_CDN_BASE}/web/images/test.svg)`)
  })

